package com.example.prototype;

import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.text.TextUtils;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private EditText emailInput;
    private EditText passwordInput;
    private Button loginButton;
    private AuthRepository authRepository;
    private SessionManager sessionManager;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        emailInput = findViewById(R.id.emailInput);
        passwordInput = findViewById(R.id.passwordInput);
        loginButton = findViewById(R.id.loginButton);

        authRepository = new AuthRepository();
        sessionManager = new SessionManager(this);

        if (sessionManager.isLoggedIn()) {
            navigateToHome();
            return;
        }

        String savedEmail = sessionManager.getEmail();
        if (!TextUtils.isEmpty(savedEmail)) {
            emailInput.setText(savedEmail);
        }

        loginButton.setOnClickListener(v -> attemptLogin());
    }

    private void attemptLogin() {
        String email = emailInput.getText().toString().trim();
        String password = passwordInput.getText().toString();

        if (TextUtils.isEmpty(email)) {
            emailInput.setError("Email required");
            return;
        }

        if (TextUtils.isEmpty(password)) {
            passwordInput.setError("Password required");
            return;
        }

        AuthResult result = authRepository.login(email, password);
        if (result.isSuccess()) {
            sessionManager.saveSession(email, result.getAuthToken());
            navigateToHome();
        } else {
            Toast.makeText(this, result.getErrorMessage(), Toast.LENGTH_SHORT).show();
        }
    }

    private void navigateToHome() {
        startActivity(new Intent(this, HomeActivity.class));
        finish();
    }
}

class SessionManager {
    private static final String PREF_NAME = "user_session";
    private static final String KEY_EMAIL = "key_email";
    private static final String KEY_AUTH_TOKEN = "key_auth_token";
    private final SharedPreferences sharedPreferences;

    SessionManager(Context context) {
        sharedPreferences = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
    }

    void saveSession(String email, String authToken) {
        sharedPreferences.edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_AUTH_TOKEN, authToken)
                .apply();
    }

    String getEmail() {
        return sharedPreferences.getString(KEY_EMAIL, "");
    }

    String getAuthToken() {
        return sharedPreferences.getString(KEY_AUTH_TOKEN, "");
    }

    boolean isLoggedIn() {
        return !TextUtils.isEmpty(getAuthToken());
    }

    void clearSession() {
        sharedPreferences.edit().clear().apply();
    }
}

class AuthRepository {

    AuthResult login(String email, String password) {
        if ("demo@example.com".equalsIgnoreCase(email) && "password123".equals(password)) {
            return new AuthResult(true, "demo_auth_token_123456", null);
        }
        return new AuthResult(false, null, "Invalid credentials");
    }
}

class AuthResult {
    private final boolean success;
    private final String authToken;
    private final String errorMessage;

    AuthResult(boolean success, String authToken, String errorMessage) {
        this.success = success;
        this.authToken = authToken;
        this.errorMessage = errorMessage;
    }

    boolean isSuccess() {
        return success;
    }

    String getAuthToken() {
        return authToken;
    }

    String getErrorMessage() {
        return errorMessage;
    }
}

class HomeActivity extends AppCompatActivity {

    private SessionManager sessionManager;
    private Button logoutButton;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_home);

        sessionManager = new SessionManager(this);
        logoutButton = findViewById(R.id.logoutButton);

        if (!sessionManager.isLoggedIn()) {
            startActivity(new Intent(this, LoginActivity.class));
            finish();
            return;
        }

        logoutButton.setOnClickListener(v -> {
            sessionManager.clearSession();
            startActivity(new Intent(this, LoginActivity.class));
            finish();
        });
    }
}